<svg viewBox="0 0 700 320" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Banka Havalesi vs. Stablecoin Transferi — İşlem Süresi</text>
  <text x="20" y="50" fill="#a1a1aa" font-size="13" font-family="sans-serif">Hyundai Card'ın ABD-Meksika pilotuna göre (9 Temmuz 2026)</text>
  <text x="20" y="100" fill="#d4d4d8" font-size="14" font-weight="700" font-family="sans-serif">Banka havalesi (SWIFT)</text>
  <rect x="20" y="112" width="640" height="34" fill="#f87171"/>
  <text x="640" y="135" fill="#fafafa" font-size="14" font-weight="700" text-anchor="end" font-family="sans-serif">~210 dk (3-4 sa)</text>
  <text x="20" y="200" fill="#d4d4d8" font-size="14" font-weight="700" font-family="sans-serif">Stablecoin (Avalanche üzerinden USDT)</text>
